import React from 'react';
import { Mail, Phone } from 'lucide-react';

const NotificationIndicators = ({ notification }) => {
  if (!notification) {
    return (
      <span className="text-gray-400 text-xs">No notifications</span>
    );
  }

  const { ticketEmailSent, ticketSmsSent, resolutionEmailSent, resolutionSmsSent } = notification;

  return (
    <div className="flex items-center space-x-2">
      {/* Email indicators */}
      {ticketEmailSent && (
        <div className="relative group">
          <Mail className="w-4 h-4 text-green-600" title="Ticket email sent" />
          <span className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-1 px-2 py-1 text-xs text-white bg-gray-900 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
            Ticket email sent
          </span>
        </div>
      )}

      {resolutionEmailSent && (
        <div className="relative group">
          <Mail className="w-4 h-4 text-blue-600" title="Resolution email sent" />
          <span className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-1 px-2 py-1 text-xs text-white bg-gray-900 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
            Resolution email sent
          </span>
        </div>
      )}

      {/* SMS indicators */}
      {ticketSmsSent && (
        <div className="relative group">
          <Phone className="w-4 h-4 text-green-600" title="Ticket SMS sent" />
          <span className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-1 px-2 py-1 text-xs text-white bg-gray-900 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
            Ticket SMS sent
          </span>
        </div>
      )}

      {resolutionSmsSent && (
        <div className="relative group">
          <Phone className="w-4 h-4 text-blue-600" title="Resolution SMS sent" />
          <span className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-1 px-2 py-1 text-xs text-white bg-gray-900 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
            Resolution SMS sent
          </span>
        </div>
      )}

      {/* If no notifications sent */}
      {!ticketEmailSent && !ticketSmsSent && !resolutionEmailSent && !resolutionSmsSent && (
        <span className="text-gray-400 text-xs">None</span>
      )}
    </div>
  );
};

export default NotificationIndicators;
